import { useContext, useEffect, useState } from "react"
import AppContext from "../../context"
import { useNavigate, useLocation, useParams } from "react-router-dom"
import { MachineEntity } from "../../entities/MachineEntity"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import styles from './DashboardLevel3.module.css'
import { formatDate } from "date-fns"
import sensorImage from "../../assets/images/sensor_image.png"
import { CenterlineService, DashboardCenterlineService } from "../../services/centerline"
import { CenterlineEntity, DashboardCenterlineLevel3 } from "../../entities/CenterlineEntity"
import Gauge from "../../components/Gauge/Gauge"
import { FaRegCircleCheck } from "react-icons/fa6"
import { MdOutlineCancel } from "react-icons/md"

interface FilterType {
    start_date: Date
    end_date: Date
}

interface DashboardLevel3CenterlinePageProps {
    realtime: boolean
    refresh: number
    filterDate: FilterType
    onFilterDateChange: (newFilter: FilterType) => void
}

const DashboardLevel3CenterlinePage: React.FC<DashboardLevel3CenterlinePageProps> = ({ realtime, refresh, filterDate, onFilterDateChange }) => {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextVersion = context.version
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    const navigate = useNavigate()
    const location = useLocation()
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    const { linkUpId } = useParams()
    const { link_up, category_sensor } = location.state || {}

    const [machineCenterlineData, setMachineCenterlineData] = useState<{ [type: string]: CenterlineEntity[] }>({})
    const [tableDataCenterline, setTableDataCenterline] = useState<{ [id: string]: DashboardCenterlineLevel3 | undefined }>({})

    interface DashboardLevel2State {
        link_up_id: number
        link_up: string

        centerline_green: number
        centerline_yellow: number
        centerline_red: number

        machine_ool: number[]
    }

    const [level2Data, setLevel2Data] = useState<{ [type: string]: DashboardLevel2State }>({})
    // ========================================= STATE VIEW =========================================  //


    // ========================================= FUNCTIONS =========================================  //
    const generateDataMachineCenterline = async () => {
        if (Object.keys(machineCenterlineData).length == 0) { contextShowLoadingFunc(true) }
        try {
            const resp = await CenterlineService.GetAllCenterline(linkUpId)

            const data: { [type: string]: CenterlineEntity[] } = {}
            for (let i = 0; i < resp.length; i++) {
                if (data[resp[i].centerline_tipe] == undefined) {
                    data[resp[i].centerline_tipe] = []
                }
                data[resp[i].centerline_tipe].push(resp[i])
            }

            setMachineCenterlineData(data)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3, }))
        } finally {
            if (Object.keys(machineCenterlineData).length == 0) { contextShowLoadingFunc(false) }
        }
    }

    const generateDataCenterline = async () => {
        try {
            if (linkUpId) {
                let resp: DashboardCenterlineLevel3[] = []
                if (realtime) {
                    resp = await DashboardCenterlineService.DashboardLevel3Realtime(Number(linkUpId))

                    onFilterDateChange({ start_date: new Date(), end_date: new Date() })
                    localStorage.removeItem("cache")
                } else {
                    const start_date = formatDate(filterDate.start_date, 'yyyy-MM-dd')
                    const end_date = formatDate(filterDate.end_date, 'yyyy-MM-dd')

                    resp = await DashboardCenterlineService.DashboardLevel3(start_date, end_date, Number(linkUpId))
                    localStorage.setItem("cache", JSON.stringify({ ...filterDate, realtime }))
                }

                const data: { [id: string]: DashboardCenterlineLevel3 } = {}
                const newLevel2ByType: { [type: string]: DashboardLevel2State } = {}
                for (let i = 0; i < resp.length; i++) {
                    const row = resp[i]
                    data[`${row.centerline_id}`] = row

                    const machine = Object.values(machineCenterlineData).flat().find(m => m.centerline_id === row.centerline_id)
                    if (!machine) continue

                    const machineType = machine.centerline_tipe

                    if (!newLevel2ByType[machineType]) {
                        newLevel2ByType[machineType] = {
                            link_up_id: link_up.link_up_id,
                            link_up: link_up.link_up,
                            centerline_green: 0,
                            centerline_yellow: 0,
                            centerline_red: 0,
                            machine_ool: [],
                        }
                    }

                    newLevel2ByType[machineType].centerline_green += row.centerline_green
                    newLevel2ByType[machineType].centerline_yellow += row.centerline_yellow
                    newLevel2ByType[machineType].centerline_red += row.centerline_red

                    if (row.centerline_red > 0) {
                        newLevel2ByType[machineType].machine_ool.push(machine.centerline_id)
                    }
                }

                for (const type in newLevel2ByType) {
                    newLevel2ByType[type].machine_ool = Array.from(new Set(newLevel2ByType[type].machine_ool))
                }

                setLevel2Data(newLevel2ByType)
                setTableDataCenterline(data)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3 }))
        }
    }

    const generateData = async () => {
        if (realtime) {
            if (contextVersion.centerline != undefined) { await generateDataCenterline() }
        } else {
            resetAllData()
            contextShowLoadingFunc(true)
            // langsung tampilkan ketika udah ada yg selesai satu
            const promise = []
            if (contextVersion.centerline != undefined) { promise.push(generateDataCenterline()) }
            try { await Promise.any(promise) } catch { }
            contextShowLoadingFunc(false)
        }
    }

    const resetAllData = () => {
        setLevel2Data((prev) => {
            const reset: typeof prev = {}
            for (const type in prev) {
                reset[type] = {
                    ...prev[type],
                    centerline_green: 0,
                    centerline_yellow: 0,
                    centerline_red: 0,
                    machine_ool: [],
                }
            }
            return reset
        })
        setTableDataCenterline({})
    }

    useEffect(() => {
        if (Object.keys(machineCenterlineData).length > 0) {
            generateData()
            if (realtime) {
                const interval = setInterval(generateData, 2000)

                return () => {
                    clearInterval(interval)
                }
            }
        }
    }, [contextAccessToken, realtime, linkUpId, machineCenterlineData, refresh])

    // generate once
    useEffect(() => {
        generateDataMachineCenterline()
    }, [])
    // =========
    // ========================================= FUNCTIONS =========================================  //


    return <div
        className={styles.cardWrapper}
        style={{
            gridTemplateColumns: Object.keys(machineCenterlineData).length === 1 ? '1fr' : 'repeat(2, 1fr)',
            gridAutoRows: Object.keys(machineCenterlineData).length <= 2 ? '1fr' : undefined
        }}
    >
        {Object.keys(machineCenterlineData).map((val) => {
            const row = machineCenterlineData[val]
            return < div className={styles.cardParent} key={val} >

                <div className={styles.cardParentHeader}>
                    <div className={styles.titleHeader}>
                        {val} Overall
                    </div>

                    <div className={styles.bodyHeader}>
                        <div className={styles.bodyHeaderLeft}>
                            <div className={styles.itemHeaderLeft}>
                                <div>Total Machine OOL</div>
                                <div className={styles.oolNumber}>{level2Data[val]?.machine_ool?.length ?? 0}</div>
                            </div>
                            <div className={styles.itemHeaderLeft}>
                                <div>Centerline Normal</div>
                                <div className={`${styles.oolNumber} ${styles.cenNumberNormal}`}>{level2Data[val]?.centerline_green}</div>
                            </div>
                            <div className={styles.itemHeaderLeft}>
                                <div>Centerline Warning</div>
                                <div className={`${styles.oolNumber} ${styles.cenNumberWarning}`}>{level2Data[val]?.centerline_yellow}</div>
                            </div>
                            <div className={styles.itemHeaderLeft}>
                                <div>Centerline Alarm</div>
                                <div className={`${styles.oolNumber} ${styles.cenNumberAlarm}`}>{level2Data[val]?.centerline_red}</div>
                            </div>
                        </div>

                        <div className={styles.bodyHeaderRight}>
                            <div className={styles.imgWrapper}>
                                <img src={sensorImage} alt="centerline image" className={styles.imgHeader} />
                            </div>
                        </div>
                    </div>
                </div>

                <div className={styles.cardParentBodyWrapper}>
                    <div className={styles.cardParentBody} style={{ gridTemplateColumns: Object.keys(machineCenterlineData).length > 1 ? "repeat(2, 1fr)" : "repeat(4, 1fr)" }}>
                        {row.map((m) => {
                            const data = tableDataCenterline[`${m.centerline_id}`]

                            return <div key={m.centerline_id} className={styles.gridItemCenter}
                                onClick={() => navigate(`/dashboard/l4/${m.centerline_id}`, {
                                    state: {
                                        dashboard_type: "centerline",
                                        machine: m.parameter_name,
                                    },
                                })}>

                                {data && (
                                    <>
                                        <div className={styles.gridCenterHeader}>
                                            <h3>{data.parameter_name}</h3>
                                            <p>{realtime ? formatDate(data.last_centerline_data.created_at, "HH:mm:ss") : formatDate(data.last_centerline_data.created_at, "yyyy-MM-dd HH:mm:ss")}</p>
                                        </div>
                                        <div className={styles.gridCenterContent}>
                                            {m.centerline_display_type == 'gauge'
                                                ? <>
                                                    <div className={styles.warningAlarm}>
                                                        <div>{data.last_centerline_data.alarm_limit_bottom ?? "-"}</div>
                                                        <div>{data.last_centerline_data.warning_limit_bottom ?? "-"}</div>
                                                        <div>{data.last_centerline_data.warning_limit ?? "-"}</div>
                                                        <div>{data.last_centerline_data.alarm_limit ?? "-"}</div>
                                                    </div>
                                                    <div className={styles.gaugeContent}>
                                                        <Gauge
                                                            value={data.last_centerline_data.value}
                                                            topLimitWarn={data.last_centerline_data.warning_limit}
                                                            topLimitAlarm={data.last_centerline_data.alarm_limit}
                                                            bottomLimitWarn={data.last_centerline_data.warning_limit_bottom}
                                                            bottomLimitAlarm={data.last_centerline_data.alarm_limit_bottom}
                                                            height={220}
                                                            width={220}
                                                            unit={m.centerline_unit}
                                                        />
                                                    </div>
                                                </>
                                                : <>
                                                    <div className={`${styles.booleanContent} ${data.last_centerline_data.value == 1 ? '' : styles.notOk}`}>
                                                        <div className={styles.booleanLeft}>
                                                            <h2>Status</h2>
                                                            <h2>{data.last_centerline_data.value == 1 ? 'OK' : 'Not OK'}</h2>
                                                        </div>
                                                        <div className={styles.booleanRight}>
                                                            <div className={styles.booleanStatus}>
                                                                {data.last_centerline_data.value == 1 ? <FaRegCircleCheck size={25} /> : <MdOutlineCancel size={25} />}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </>}
                                        </div>
                                    </>
                                )}
                            </div>
                        })}
                    </div>
                </div>

            </div>
        })}
    </div>
}

export default DashboardLevel3CenterlinePage